const body = $json.body ?? $json;
const traceId = body.traceId || body.jobId || `trace-${Date.now()}`;

// A. Input cleaning
let userText = String(body.userText || '').trim();
userText = userText.replace(/[\u2018\u2019]/g, "'").replace(/[\u201C\u201D]/g, '"');
userText = userText.replace(/[ \t\n\r]+/g, ' ').trim();
userText = userText.slice(0, 500);
const userTextRaw = String(body.userText || '');

// B. Language / locale
const locale = String(body.locale || body.voiceLanguage || 'en').slice(0, 16);

// C. System prompt from agent settings
const systemPrompt = String(body.systemPrompt || '').trim().slice(0, 2000);

// D. Per-session config hints (model selection, RAG overrides) from Python agent
const config = (body.config && typeof body.config === 'object') ? body.config : {};

// E. Conversation context compression: keep last 10, strip empty
const rawMessages = Array.isArray(body.messages) ? body.messages : [];
const messages = rawMessages
  .filter(m => m && String(m.content || '').trim().length > 0)
  .slice(-10);

return [{ json: {
  traceId,
  workflowId: body.workflowId || '6KFFgjd26nF0kNCA',
  requestedByWorkflowId: '6KFFgjd26nF0kNCA',
  roomId: body.roomId || null,
  jobId: body.jobId || null,
  deviceId: body.deviceId || null,
  userText,
  userTextRaw,
  messages,
  locale,
  systemPrompt,
  config,
  action: body.action || null,
  params: body.params || null,
  startedAt: new Date().toISOString()
}}];

// Priority: payload.config > n8n Variables > hardcoded defaults
// Configure models, RAG, and routing via n8n UI → Settings → Variables
const body = $json;
const pCfg = body.config || {};

function resolve(pv, varName, def) {
  if (pv != null && pv !== '') return pv;
  try { const nv = $vars[varName]; if (nv != null && nv !== '') return nv; } catch {}
  return def;
}
function resolveBool(pv, varName, def) {
  const v = resolve(pv, varName, def);
  if (typeof v === 'boolean') return v;
  return String(v).toLowerCase() !== 'false';
}

const cfg = {
  // --- Intent LLM (fast/cheap model for classification) ---
  intentModel:       resolve(pCfg.intentModel,       'INTENT_MODEL',        'ministral-3:8b'),
  intentBaseUrl:     resolve(pCfg.intentBaseUrl,     'INTENT_BASE_URL',     'https://ollama.drascom.uk').replace(/\/$/, ''),
  intentTemperature: parseFloat(resolve(pCfg.intentTemperature, 'INTENT_TEMPERATURE', 0.1)) || 0.1,

  // --- Reply LLM (higher quality model for response generation) ---
  replyModel:        resolve(pCfg.replyModel,        'REPLY_MODEL',         'ministral-3:8b'),
  replyBaseUrl:      resolve(pCfg.replyBaseUrl,      'REPLY_BASE_URL',      'https://ollama.drascom.uk').replace(/\/$/, ''),
  replyTemperature:  parseFloat(resolve(pCfg.replyTemperature,  'REPLY_TEMPERATURE',  0.25)) || 0.25,
  replyMaxTokens:    parseInt(resolve(pCfg.replyMaxTokens,     'REPLY_MAX_TOKENS',   150))  || 150,

  // --- RAG (retrieval-augmented generation) ---
  // ragSource: 'foods_api' = search live menu | 'disabled' = skip RAG
  ragEnabled:  resolveBool(resolve(pCfg.ragEnabled,  null, null), 'RAG_ENABLED',  true),
  ragSource:   resolve(pCfg.ragSource,   'RAG_SOURCE',   'foods_api'),
  ragTopK:     parseInt(resolve(pCfg.ragTopK, 'RAG_TOP_K', 5)) || 5,
  ragBaseUrl:  resolve(pCfg.ragBaseUrl,  'RAG_BASE_URL', 'http://127.0.0.1:3000').replace(/\/$/, ''),
  ragSecret:   resolve(pCfg.ragSecret,   'AI_SERVER_SHARED_SECRET', ''),

  // --- Routing ---
  // Below threshold intent confidence → force fallback, no MCP call
  confidenceThreshold: parseFloat(resolve(pCfg.confidenceThreshold, 'CONFIDENCE_THRESHOLD', 0.45)) || 0.45,
  mcpEnabled: resolveBool(resolve(pCfg.mcpEnabled, null, null), 'MCP_ENABLED', true),
  mcpUrl:     resolve(pCfg.mcpUrl, 'MCP_URL', 'https://n8n.drascom.uk/webhook/XYiIkxpa4PlnddQt'),
};

return [{ json: { ...body, cfg } }];

const root = $json.body ?? $json;
const raw = root?.choices?.[0]?.message?.content || root?.replyText || root?.text || '';
let parsed = {};
if (typeof raw === 'string') {
  try {
    const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
    parsed = JSON.parse(cleaned);
  } catch { parsed = {}; }
}

// Use Resolve Config as prev (has cfg + all normalized fields)
const prev = $('Resolve Config').item.json;
const cfg = prev.cfg || {};

const VALID_INTENTS = new Set(['greeting','farewell','menu_browse','product_search','price_check','add_to_cart','view_cart','checkout','order_status','help','fallback']);
const rawIntent = VALID_INTENTS.has(parsed.intent) ? parsed.intent : 'fallback';

const rawConfidence = typeof parsed.confidence === 'number'
  ? Math.min(1, Math.max(0, parsed.confidence))
  : (rawIntent === 'fallback' ? 0.3 : 0.7);

// Quality gate: below confidence threshold → treat as fallback, skip MCP
const threshold = cfg.confidenceThreshold || 0.45;
const intent = rawConfidence >= threshold ? rawIntent : 'fallback';
const confidence = rawConfidence;

const slots = {
  productName: parsed.slots?.productName || null,
  quantity: typeof parsed.slots?.quantity === 'number' ? parsed.slots.quantity : null,
  orderId: parsed.slots?.orderId || null,
  category: parsed.slots?.category || null
};

const MCP_INTENTS = new Set(['menu_browse','product_search','price_check','add_to_cart','order_status']);
const requiresMcp = MCP_INTENTS.has(intent) && cfg.mcpEnabled !== false;

const MCP_ACTION_MAP = {
  menu_browse: 'products.list',
  product_search: 'products.search',
  price_check: 'products.search',
  add_to_cart: 'products.search',
  order_status: 'orders.status'
};
const mcpAction = parsed.mcpAction || MCP_ACTION_MAP[intent] || 'none';
const mcpQuery = parsed.mcpQuery || slots.productName || slots.category || slots.orderId || prev.userText || '';
const ask = String(parsed.ask || '');

return [{ json: { ...prev, intent, confidence, rawConfidence, slots, requiresMcp, mcpAction, mcpQuery, ask, intentRaw: raw } }];

// Retrieval-Augmented Generation: enrich context with knowledge base results
// ragSource: 'foods_api' = live menu search | 'disabled' = skip
// Future sources: 'vector_store' (pgvector embeddings), 'knowledge_base' (FAQ/policies)
const ctx = $json;
const cfg = ctx.cfg || {};

const RAG_INTENTS = new Set(['menu_browse', 'product_search', 'price_check', 'add_to_cart']);
const shouldRag = cfg.ragEnabled !== false
  && cfg.ragSource !== 'disabled'
  && RAG_INTENTS.has(ctx.intent);

if (!shouldRag) {
  return [{ json: { ...ctx, ragContext: null, ragFoods: null, ragMeta: { skipped: true, reason: 'not applicable for intent: ' + ctx.intent } } }];
}

try {
  const q = ctx.mcpQuery || ctx.userText || '';
  const limit = cfg.ragTopK || 5;
  const baseUrl = (cfg.ragBaseUrl || 'http://127.0.0.1:3000').replace(/\/$/, '');
  const url = `${baseUrl}/v1/voice/foods?limit=${limit}${q ? '&q=' + encodeURIComponent(q) : ''}`;

  const resp = await fetch(url, {
    method: 'GET',
    headers: {
      'x-ai-server-secret': cfg.ragSecret || '',
      'Accept': 'application/json'
    }
  });

  const data = await resp.json();
  const foods = data?.data?.foods || [];

  const ragContext = foods.length > 0
    ? 'Menu knowledge:\n' + foods.map(f =>
        '• ' + f.name + ': \u00a3' + parseFloat(f.price).toFixed(2)
        + (f.available ? ' (available)' : ' (unavailable)')
        + (f.cardSummary ? ' \u2014 ' + f.cardSummary : '')
      ).join('\n')
    : 'No matching menu items found.';

  return [{ json: {
    ...ctx,
    ragContext,
    ragFoods: foods,
    ragMeta: { source: cfg.ragSource, topK: limit, query: q, count: foods.length }
  }}];
} catch (err) {
  // RAG failure is non-fatal: log and proceed without enrichment
  return [{ json: { ...ctx, ragContext: null, ragFoods: null, ragMeta: { error: String(err.message || err) } } }];
}

const hasMcp = !!$json.ok || 'data' in $json || 'error' in $json;
if (hasMcp) {
  // MCP path: $json = Call MCP response. RAG Lookup ran upstream — get its output as base.
  const base = $('RAG Lookup').item.json; // has ctx + cfg + ragContext + ragFoods
  return [{ json: {
    ...base,
    mcp: {
      ok: Boolean($json.ok),
      status: Number($json.status || 0),
      data: $json.data ?? null,
      error: $json.error ?? null,
      durationMs: $json.durationMs ?? null
    }
  }}];
}
// Direct path: $json = Parse Intent output (route-intent false)
return [{ json: { ...$json, ragContext: null, ragFoods: null, ragMeta: { skipped: true }, mcp: null } }];

const ctx = $json;
const mcp = ctx.mcp || null;

// RAG section: knowledge base results formatted as prose
const ragPart = ctx.ragContext || '';

// MCP section: live structured data (prices, availability)
let mcpPart = '';
if (mcp?.ok && mcp.data?.foods?.length > 0) {
  mcpPart = 'Live availability:\n' + mcp.data.foods.slice(0, 5).map(f =>
    '- ' + f.name + ': \u00a3' + f.price + ' (' + (f.available ? 'available' : 'unavailable') + ')'
  ).join('\n');
} else if (mcp && !mcp.ok) {
  mcpPart = 'Data lookup failed: ' + (mcp.error?.message || 'unknown error');
} else if (mcp?.ok && (!mcp.data?.foods || mcp.data.foods.length === 0)) {
  mcpPart = 'No matching items found in the menu.';
}

// Combine: RAG knowledge first, then live MCP data
const contextBlock = [ragPart, mcpPart].filter(Boolean).join('\n\n') || '(no additional data)';

// Typed UI actions for deterministic intent paths
const actions = [];
if (ctx.intent === 'menu_browse') {
  actions.push({ name: 'navigate', params: { screen: 'Menu' } });
} else if (ctx.intent === 'checkout') {
  actions.push({ name: 'navigate', params: { screen: 'Cart' } });
} else if (ctx.intent === 'view_cart') {
  actions.push({ name: 'show_order_summary', params: { items: [], total: 0 } });
} else if (ctx.intent === 'order_status') {
  actions.push({ name: 'navigate', params: { screen: 'OrderStatus' } });
} else if (ctx.intent === 'add_to_cart' && mcp?.data?.foods?.length > 0) {
  const food = mcp.data.foods[0];
  actions.push({ name: 'add_to_cart', params: {
    productId: food.id,
    productName: food.name,
    quantity: ctx.slots?.quantity || 1,
    price: parseFloat(food.price) || 0
  }});
}

return [{ json: { ...ctx, contextBlock, actions } }];

const rawRoot = $json.body ?? $json;
const llmText = String(rawRoot?.choices?.[0]?.message?.content || '').trim();
const ctx = $('Build Reply Context').item.json;

// Fallback chain: LLM output → clarifying question → intent-based default
const fallback = ctx.ask
  ? ctx.ask
  : ctx.intent === 'fallback'
    ? "I'm not sure I understood that. Could you rephrase?"
    : 'How can I help you with your order?';

const replyText = llmText || fallback;

// Validate actions against allowlist (defense against hallucinated action names)
const ALLOWED = new Set(['navigate', 'add_to_cart', 'show_order_summary']);
const actions = (ctx.actions || []).filter(a => ALLOWED.has(a.name));

return [{ json: {
  replyText,
  actions,
  meta: {
    intent: ctx.intent,
    confidence: ctx.confidence,
    rawConfidence: ctx.rawConfidence,
    slots: ctx.slots,
    requiresMcp: ctx.requiresMcp,
    mcpAction: ctx.mcpAction,
    mcp: ctx.mcp,
    rag: ctx.ragMeta,
    traceId: ctx.traceId,
    locale: ctx.locale,
    model: {
      intent: ctx.cfg?.intentModel,
      reply: ctx.cfg?.replyModel
    }
  }
}}];
